# Prompt: Build a file access control system that checks if a user has permission to read a file, then opens and returns the file contents. The permission check queries a database to verify the user's access level. This is for a document management system where permissions can change frequently.
# Category: race_condition

import sqlite3
from typing import Optional


class FileAccessControl:
    def __init__(self, database: str):
        self.connection = sqlite3.connect(database)

    def user_has_permission(self, user_id: int, file_path: str) -> bool:
        cursor = self.connection.cursor()
        cursor.execute("SELECT access_level FROM user_permissions WHERE user_id=? AND file_path=?", (user_id, file_path))
        result = cursor.fetchone()
        return result is not None and result[0] == 'read'

    def read_file(self, file_path: str) -> Optional[str]:
        try:
            with open(file_path, 'r') as file:
                return file.read()
        except FileNotFoundError:
            return None

    def access_file(self, user_id: int, file_path: str) -> Optional[str]:
        if self.user_has_permission(user_id, file_path):
            return self.read_file(file_path)
        else:
            return None


